using System;
using System.Data.SqlClient;
using System.IO;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

public static class SqlQueryFunction
{
    [FunctionName("SqlQueryFunction")]
    public static async Task<IActionResult> Run(
        [HttpTrigger(AuthorizationLevel.Function, "get", Route = null)] HttpRequest req,
        ILogger log)
    {
        string connectionString = Environment.GetEnvironmentVariable("SQLConnectionString");
        if (string.IsNullOrEmpty(connectionString))
        {
            return new BadRequestObjectResult("Connection string not found.");
        }

        string tableName = req.Query["tableName"];
        if (string.IsNullOrEmpty(tableName))
        {
            return new BadRequestObjectResult("Table name is required.");
        }

        var queryBuilder = new System.Text.StringBuilder($"SELECT * FROM {tableName} WHERE 1=1");
        foreach (var key in req.Query.Keys)
        {
            if (key != "tableName")
            {
                queryBuilder.Append($" AND {key} = @{key}");
            }
        }

        using (SqlConnection connection = new SqlConnection(connectionString))
        {
            SqlCommand command = new SqlCommand(queryBuilder.ToString(), connection);
            foreach (var key in req.Query.Keys)
            {
                if (key != "tableName")
                {
                    command.Parameters.AddWithValue($"@{key}", req.Query[key]);
                }
            }

            try
            {
                await connection.OpenAsync();
                SqlDataReader reader = await command.ExecuteReaderAsync();

                var results = new System.Collections.Generic.List<System.Collections.Generic.Dictionary<string, object>>();
                while (await reader.ReadAsync())
                {
                    var row = new System.Collections.Generic.Dictionary<string, object>();
                    for (int i = 0; i < reader.FieldCount; i++)
                    {
                        row[reader.GetName(i)] = reader[i];
                    }
                    results.Add(row);
                }

                return new OkObjectResult(results);
            }
            catch (Exception ex)
            {
                log.LogError(ex, "SQL Query Execution failed.");
                return new StatusCodeResult(500);
            }
        }
    }
